        r'\bbefore\s+([A-Z][a-z]+)',
        r'\bdue\s+(?:on\s+)?([A-Z][a-z]+\s+\d{1,2}(?:,\s*\d{4})?)',
        r'\b(?:today|tomorrow|next week|next month|EOD|end of day)\b'
    ]
