        r'\b([A-Z][a-z]+)\s+will\s+',
        r'\blet\'s ask\s+([A-Z][a-z]+)\s+to\s+',
        r'\b([A-Z][a-z]+)\s+should\s+',
        r'\b([A-Z][a-z]+)\s+needs to\s+',
        r'\b([A-Z][a-z]+)\s+to\s+',
